#!run
import {showWidget,showIframe} from "@acepad/widget";
import {open} from "@acepad/browser";
export async function main(f,opt={}){
  if(opt.window){
    return window.open(f);
  }
  if(typeof f==="string" && f.match(/^https?:/)){
      return showIframe(f,opt);
  }else{
      return showIframe(this.resolve(f),opt);
  }
}